module asyn_fifo(
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [7:0] wdata,
    output wfull, rempty,
    output [7:0] rdata
);

dual_port_RAM #(.WIDTH(8), .DEPTH(16)) ram (
    .wclk(wclk),
    .wenc(wen),
    .waddr(waddr_bin[$clog2(DEPTH)-1:0]),
    .wdata(wdata),
    .rclk(rclk),
    .renc(ren),
    .raddr(raddr_bin[$clog2(DEPTH)-1:0]),
    .rdata(rdata)
);

reg [$clog2(DEPTH)-1:0] waddr_bin;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        waddr_bin <= 0;
    else if (winc)
        waddr_bin <= waddr_bin + 1;
end
wire [3:0] wptr;
assign wptr = {waddr_bin[3], waddr_bin[3]^waddr_bin[2], waddr_bin[2]^waddr_bin[1], waddr_bin[1]^waddr_bin[0]};
reg [3:0] wptr_buff;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        wptr_buff <= 0;
    else if (winc)
        wptr_buff <= wptr;
end
assign wen = winc && wrstn;

reg [$clog2(DEPTH)-1:0] raddr_bin;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        raddr_bin <= 0;
    else if (rinc)
        raddr_bin <= raddr_bin + 1;
end
wire [3:0] rptr;
assign rptr = {raddr_bin[3], raddr_bin[3]^raddr_bin[2], raddr_bin[2]^raddr_bin[1], raddr_bin[1]^raddr_bin[0]};
reg [3:0] rptr_buff;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        rptr_buff <= 0;
    else if (rinc)
        rptr_buff <= rptr;
end
assign ren = rinc && rrstn;

assign wfull = (wptr == {~rptr_buff[3], rptr_buff[2:0]});
assign rempty = (rptr == wptr);
endmodule
